from dataclasses import dataclass

@dataclass
class Response:
    status_code: int
    body: str

    def iter_content(self):
        yield self.body

class ChatService:
    def complete(self, prompt: str) -> Response:
        return Response(status_code=200, body=f"Response to: {prompt}")

    def stream(self, prompt: str) -> Response:
        if not prompt:
            return Response(status_code=400, body="")
        # Bug: wrong status code
        return Response(status_code=500, body=f"Streaming: {prompt}")
